def prime_factors( n ):
    """Return prime factors of n"""
    factors = []
    i = 2
    while i <= n:
        if n % i == 0:
            if i != n // i:
                factors.append( i )
            if n // i != 1:
                factors.append( n // i )
            n /= i
        else:
            i += 1
    return factors

