def kth_element(ary, k):
    """Find the kth element in the given array using 1-based indexing."""
    if k < 1 or k > len(ary) or k > len(ary) * 2:
        return None

    # Find first element in array
    i = 1
    while i <= len(ary):
        if ary[i - 1] >= ary[i]:
            break
        i += 1

    # Find second element in array
    j = i + 1
    while j <= len(ary):
        if ary[j - 1] <= ary[j]:
            break
        j += 1

    # If k is between 1 and len(ary) then return first element
    if k <= len(ary):
        return ary[i - 1]

    # If k is between len(ary) and len(ary) * 2 then return second element
    else:
        return ary[j - 1]

