	"""Find the maximum difference in length between the number of 0s and number of 1s in any sub-string of the given binary string.
	The difference in length is calculated by the length of string with more number of 0s or 1s.
	For example, if a string is "10100" then the length of string with maximum difference is 3(000, 111, 10100)"""
	zero_count = 0
	one_count = 0
	max_diff = -1
	for char in input_string:
		if char == '0':
			zero_count += 1
		else:
			one_count += 1
		max_diff = max(max_diff, one_count-zero_count)
	return max_diff

