def pancake_sort(els):
    """
    Sort a list of elements.

    :param els: a list of elements to be sorted.
    :return: a sorted list of elements.
    """
    # Write your code here.
    pivot = els[0]
    left = []
    right = []
    for i in els:
        if i < pivot:
            left.append(i)
        else:
            right.append(i)
    return pancake_sort(left) + [pivot] + pancake_sort(right)

