def lexicographic_count(list_of_elements, element):
    """This function will take in an iterable of elements and an element, and it will return the count of the element in the iterable, counting the occurrences by lexicographic ordering."""
    count = 0
    for lexicographically_equal, element in enumerate(list_of_elements):
        if element == element:
            count+=1
    return count

