def re_arrange_array(ary, n):
    """
    Write a function that takes in an array and an integer n, and re-arranges the first n elements of the given array so that all negative elements appear before positive ones, and where the relative order among negative and positive elements is preserved.
    """
    if n == 0:
        return ary
    else:
        positive = []
        negative = []
        for i in range(len(ary)):
            if ary[i] >= 0:
                positive.append(ary[i])
            else:
                negative.append(ary[i])
        negative = negative[:n] + positive
        return negative + re_arrange_array(positive, n)

def re_arrange_array(ary, n):
    """This function reads an array and an integer n, and rearranges the first n elements of the given array so that all negative elements appear before positive ones, and where the relative order among negative and positive elements is preserved."""
    if len(ary) == 0:
        return []
    elif len(ary) < n:
        return ary
    elif len(ary) == n:
        return sorted(ary, reverse=True)
    else:
        return sorted(ary)[:n] + sorted(ary[n:], reverse=True)

