    """
    :param grades: a tuple of integers
    :param bonuses: a tuple of integers
    :return: a tuple of integers
    """
    def get_points(grades, bonuses):
        points = 0
        for grade, bonus in zip(grades, bonuses):
            points += grade * bonus
        return points

    def get_max_score(g1, b1, g2, b2):
        points1 = get_points(g1, b1)
        points2 = get_points(g2, b2)
        if points1 > points2:
            return g1, b1, g2, b2
        else:
            return g2, b2, g1, b1

    grades = sorted(grades, reverse=True)
    bonuses = sorted(bonuses, reverse=True)
    score = 0
    for grade, bonus in zip(grades, bonuses):
        score += grade * bonus
    return get_max_score(grades, bonuses, grades[0], bonuses[0])

def maximize_elements(operations, elements):
    """Maximize the elements"""
    max_elements = []
    for operation, element in zip(operations, elements):
        if element > max_elements[0][1]:
            max_elements = [(element, operation)]
        elif element == max_elements[0][1]:
            max_elements.append((element, operation))
        else:
            # Swap elements
            max_elements = [(element, operation)] + max_elements
    return max_elements

