def newman_prime( n ):
    """The nth Newman–Shanks–Williams prime number.

    Returns:
        int: The nth Newman–Shanks–Williams prime number.
    """
    if n < 3:
        return 2

    if n <= 10:
        return 7

    # n is greater than 10.
    # Find the nth prime number using sieve of Eratosthenes.
    a = 2
    b = n
    while a < b:
        if a == 2:
            a += 1
        elif a == 3:
            a += 2
        elif a == 5:
            a += 4
        else:
            a += 6

        if a > b:
            break

        if is_prime(a):
            b = a
        else:
            a += 2

    # Find the nth Williams prime number.
    c = b + 2
    while c < n:
        if is_prime(c):
            b = c
        else:
            c += 2

    # Find the nth Shanks prime number.
    d = b + 6
    while d < n:
        if is_prime(d):
            b = d
        else:
            d += 6

    return b

