def max_sub_array_sum_repeated_helper(ary, k, n, start, max_sum):
    if k == 0:
        return max_sum
    cur_sum = 0
    for i in range(start, n):
        cur_sum += ary[i] * k
        max_sum = max(max_sum, cur_sum)
        k -= 1
    return max_sum

