    if m == 1:
        return max(used)
    if m == 2:
        return max(used + [-1]*(k-1))
    cur_sum = max(used)
    for i in range(3, m+1, 2):
        cur_sum = max(cur_sum, max(used + [-1]*(k-i)))
    return cur_sum
