    """
    Write a function to find the largest sum of a contiguous array in the modified array which is formed by repeating the given array k times."""
    max_sum = float('-inf')  # Initialize the max_sum to negative infinity
    for i in range(m):
        if i < k:
            max_sum = max(max_sum, sum(used))  # If `i` is less than `k`, max_sum is the sum of all the elements in the list
        else:
            max_sum = max(max_sum, max(used + [-1]*(k-i)))  # If `i` is greater than or equal to `k`, max_sum is the max of max_sum and the sum of the elements in the list and the elements in the list with a minus one added `k-i` times
    return max_sum
