def count_no_of_ways( n, k ):
    """Returns number of ways of painting a fence with n posts and k colors such that at most 2 adjacent posts have the same color."""
    if n == 1:
        return k
    if n == 2:
        return k * k
    if n == 3:
        return k * (k - 1) * k
    return k * (k - 1) * (k - 2) * count_no_of_ways( n - 2, k )

