    """Return the sum of all divisors of an integer."""
    if n<1:
        return 0
    if n<4:
        return 1
    if n%2==0 or n%3==0:
        return sum_div( n/2 ) + sum_div( n/3 ) + 1
    # n is odd, at least one prime factor is also odd
    return sum_div( n/5 ) + sum_div( n/7 ) + 1

