    if len( s1 ) != len( s2 ):
        return False

    #Make a dictionary of frequency of characters in s1
    d1 = {}
    for c in s1:
        if c in d1:
            d1[c] += 1
        else:
            d1[c] = 1

    #Make a dictionary of frequency of characters in s2
    d2 = {}
    for c in s2:
        if c in d2:
            d2[c] += 1
        else:
            d2[c] = 1

