    largest = (Elements[0], Elements[1])
    for i in range(2, len(Elements)):
        for j in range(i+1, len(Elements)):
            newProduct = Elements[i] * Elements[j]
            if newProduct > product:
                product = newProduct
                largest = (Elements[i], Elements[j])

    # Return largest pair
    return largest


