def round_and_sum(Numbers):
    '''Rounds any float to the nearest integer then sums all numbers in a list of numbers.
    Returns the total sum of numbers multiplied by the length of the list.'''
    sum = 0
    for num in Numbers:
        if type(num)==float:
            sum += int(round(num))
        else:
            sum += num
    return sum * len(Numbers)

