    """Count the number of bidirectional tuple pairs.

    I.e. count the number of tuples (a, b) such that there exists a tuple (b, a).
    """
    n = len(sequences)
    if n < 2:
        return 0
    if n == 2:
        return count_bidirectional(sequences[0]) + count_bidirectional(sequences[1])
    elif n == 3:
        return count_bidirectional(sequences[0]) + count_bidirectional(sequences[1]) + count_bidirectional(sequences[2])
    else:
        return count_bidirectional(sequences[0]) + count_bidirectional(sequences[1]) + count_bidirectional(sequences[2]) + 2 * count_bidirectional(sequences[3])

