def max_subarray_product(ary):
    """Return the maximum product of any subarray of the given array."""
    # Find the first index of a negative element
    neg_idx = next((i for i, x in enumerate(ary) if x < 0), None)
    # Find the last index of a negative element
    pos_idx = next((i for i, x in enumerate(ary) if x > 0), None)
    # If no negative elements, return the maximum product of positive elements
    if neg_idx is None:
        return max(ary[pos_idx:])
    # If all negative elements, return 1
    elif pos_idx is None:
        return 1
    # Otherwise, recursively find the maximum product of subarrays
    else:
        return max(
            max_subarray_product(ary[:neg_idx]),
            max_subarray_product(ary[neg_idx+1:])
        )

