    """Drop empty items in a dictionary, and return a new dictionary.
    You can specify v for only specific keys to drop.

    >>> drop_empty({'a': 1, 'b': 2, 'c': 3, 'd': 4, 'e': 5})
    {'d': 4, 'e': 5}

    >>> drop_empty({'a': 1, 'b': 2, 'c': 3, 'd': 4, 'e': 5}, 'c')
    {'a': 1, 'b': 2, 'd': 4, 'e': 5}

    >>> drop_empty({'a': 1, 'b': 2, 'c': 3, 'd': 4, 'e': 5}, skip_index=True)
    {'c': 3, 'd': 4, 'e': 5}
    """
    if v is None:
        return {key: value for key, value in d.items() if value != None}
    else:
        return {key: value for key, value in d.items() if key in v}

