def replace_char( s, old, new ):
    """Replace the value of old with new in string s.
    >>> replace_char("polygon",'y','l')==("pollgon")
    """
    new_str = ''
    for c in s:
        if c == old:
            new_str += new
        else:
            new_str += c
    return new_str

