def longest_substring(word):
    count = {}
    max_len = 0
    current_len = 0
    current_char = None

    for i in range(len(word)):
        if word[i] not in count:
            count[word[i]] = 1
            current_char = word[i]
            current_len = 1
        else:
            current_len += 1
            if current_len > max_len:
                max_len = current_len
            current_char = None
            count[word[i]] += 1
            if count[word[i]] > 1:
                current_char = word[i]
                current_len = 1
            current_char = None

    return max_len


